const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const API=$('Config').first().json.apiBase;
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const fedId=$json.fedId; const id=$json.id;
const SRC='https://slovakvolley.sk/page/adresare';
const isEmail=(e)=>/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(e);
const isSocial=(u)=>/facebook|instagram|twitter|x\.com|tiktok|youtube|linkedin/i.test(u);
const normUrl=(u)=>{u=String(u||'').trim();if(!u)return '';if(u.startsWith('//'))u='https:'+u;if(!/^https?:/i.test(u))u='https://'+u;return u;};
const now=new Date().toISOString();
const findClub=async(k)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:"(dedup_key='"+k+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
const findContact=async(e)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter:"(email='"+e.replace(/'/g,'')+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
let d;
try{d=await this.helpers.httpRequest({method:'GET',url:API+'/clubs/'+id,headers:{'User-Agent':'Mozilla/5.0'},json:true});}catch(e){return [{json:{id,error:'fetch:'+e.message}}];}
const name=(d.name||$json.name||'').trim(); if(!name) return [{json:{id,skip:'noname'}}];
const addr=d.address||{}; const city=(addr.city||'').trim();
const ccs=d.contacts||[];
let site=''; for(const c of ccs){if(c.type==='Web'){site=normUrl(c.value);break;}} if(isSocial(site))site='';
const dedup='SVK:'+id;
const base={federation:fedId,name,country:'Slovakia',city,dedup_key:dedup,source_url:SRC,detail_url:API+'/clubs/'+id,source_club_id:String(id),last_scraped:now};
let clubId=null;
try{ try{const rec=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/clubs/records',headers:pbH,body:Object.assign({},base,{website_url:site,website_source:site?'official_list':'none',status:'new'}),json:true});clubId=rec.id;}
  catch(e){const ex=await findClub(dedup);if(ex){const p=Object.assign({},base);if(site){p.website_url=site;p.website_source='official_list';}await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/clubs/records/'+ex.id,headers:pbH,body:p,json:true});clubId=ex.id;}else throw e;} }
catch(e){return [{json:{id,error:'club:'+e.message}}];}
const people=d.people||[];
const cands=[];
for(const c of ccs){if(c.type==='Email'){const e=(c.value||'').toLowerCase().trim();if(isEmail(e))cands.push({email:e,name:'',position:'',phone:''});}}
for(const p of people){const pc=p.contacts||[];let email='',phone='';for(const c of pc){if(c.type==='Email'&&!email)email=(c.value||'').toLowerCase().trim();if(c.type==='Phone'&&!phone)phone=(c.value||'').trim();}if(email&&isEmail(email)){const nm=[p.firstName,p.lastName].filter(Boolean).join(' ').trim();cands.push({email,name:nm,position:p.type||'',phone});}}
const seen={}; let contactsC=0;
for(const ct of cands){ if(seen[ct.email])continue; seen[ct.email]=1; try{await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/contacts/records',headers:pbH,body:{club:clubId,email:ct.email,name:ct.name,position:ct.position,phone:ct.phone,source_url:base.detail_url,source_type:'directory',verification_status:'unverified'},json:true});contactsC++;}
  catch(e){try{const ex=await findContact(ct.email);if(ex&&!ex.club)await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+ex.id,headers:pbH,body:{club:clubId},json:true});}catch(_){}}
}
return [{json:{id,name,site:site||'',contactsC}}];

